module RefModule(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1;
    reg [1:0] pipeline_reg, next;

    // State Transition Logic
    always @(*) begin
        case (pipeline_reg)
            A: next = in ? A : B;
            B: next = in ? A : B;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) pipeline_reg <= A;
        else pipeline_reg <= next;
    end

    // Output Logic
    always @(*) begin
        case (pipeline_reg)
            A: out = 0;
            B: out = 1;
        endcase
    end
endmodule
